import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Login from './pages/Login';

function App() {
  const proBackground = {
    backgroundImage: `linear-gradient(rgba(255,255,255,0.6), rgba(255,255,255,0.6)), url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?q=80&w=2000')`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundAttachment: 'fixed',
    minHeight: '100vh',
    fontFamily: "'Segoe UI', Roboto, sans-serif"
  };

  return (
    <Router>
      <div style={proBackground}>
        {/* Professional Navbar */}
        <nav style={{ 
          backgroundColor: '#0056b3', padding: '15px 60px', 
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          boxShadow: '0 4px 20px rgba(0,0,0,0.15)', position: 'sticky', top: 0, zIndex: 1000
        }}>
          <Link to="/" style={{ color: 'white', textDecoration: 'none', fontWeight: '900', fontSize: '28px', letterSpacing: '1px' }}>
            APNI MANZIL
          </Link>
          <Link to="/login" style={{ 
            backgroundColor: '#28a745', color: 'white', padding: '12px 35px', 
            borderRadius: '50px', textDecoration: 'none', fontWeight: 'bold',
            transition: '0.3s', boxShadow: '0 4px 10px rgba(0,0,0,0.2)'
          }}>
            Login / Join
          </Link>
        </nav>

        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
